def validate_redirect_uri(redirect_uri, tenant_config):
    """
    Securely validate redirect_uri using an explicit allowlist.

    SECURITY NOTE: We use exact string matching against a pre-configured allowlist
    of redirect URIs. We do NOT use substring/contains checks like
    'if domain in redirect_uri' because that is vulnerable to bypass attacks.

    For example, 'if "example.com" in redirect_uri' would incorrectly allow:
      - https://evil-example.com/callback (attacker-controlled domain)
      - https://example.com.attacker.com/callback (attacker-controlled subdomain)
      - https://attacker.com/?redirect=example.com (query string injection)

    Instead, we parse the URI and validate each component explicitly, and also
    check against an exact allowlist of pre-registered redirect URIs.
    """
    if not redirect_uri:
        return False

    # First check: exact match against allowlist (strongest validation)
    if redirect_uri in tenant_config.get("allowed_redirect_uris", []):
        return True

    # If not in exact allowlist, reject
    # Do NOT fall back to substring matching or domain contains checks
    return False


def validate_redirect_uri_components(redirect_uri):
    """
    Additional structural validation of the redirect URI.
    Ensures the URI is well-formed and uses HTTPS.
    """
    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        return False

    # Must use HTTPS (never HTTP in production)
    if parsed.scheme != "https":
        return False

    # Must have a valid hostname
    if not parsed.hostname:
        return False

    # Reject URIs with credentials embedded
    if parsed.username or parsed.password:
        return False

    # Reject fragments (not allowed in OAuth redirect URIs per RFC 6749)
    if parsed.fragment:
        return False

    return True


